import{_ as t,c as a,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"스트리밍 중단: 0 Token 문제 해결 | Antigravity-Manager","description":"Antigravity Tools의 스트리밍 중단, 0 Token 및 서명 무효 문제 해결 경로를 학습합니다. /v1/messages 또는 Gemini 스트리밍 호출을 확인하고, peek 사전 읽기 및 백오프 재시도를 이해하여 Proxy Monitor 및 로그로 빠르게 원인을 찾아내고 계정 로테이션이 필요한지 판단하세요.","frontmatter":{"title":"스트리밍 중단: 0 Token 문제 해결 | Antigravity-Manager","sidebarTitle":"자가 치유 또는 수동 개입","subtitle":"스트리밍 중단/0 Token/서명 무효: 자가 치유 메커니즘 및 문제 해결 경로","description":"Antigravity Tools의 스트리밍 중단, 0 Token 및 서명 무효 문제 해결 경로를 학습합니다. /v1/messages 또는 Gemini 스트리밍 호출을 확인하고, peek 사전 읽기 및 백오프 재시도를 이해하여 Proxy Monitor 및 로그로 빠르게 원인을 찾아내고 계정 로테이션이 필요한지 판단하세요.","tags":["faq","streaming","troubleshooting","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}'),i={name:"ko/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function s(d,e,l,n,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="스트리밍-중단-0-token-서명-무효-자가-치유-메커니즘-및-문제-해결-경로" tabindex="-1">스트리밍 중단/0 Token/서명 무효: 자가 치유 메커니즘 및 문제 해결 경로 <a class="header-anchor" href="#스트리밍-중단-0-token-서명-무효-자가-치유-메커니즘-및-문제-해결-경로" aria-label="Permalink to &quot;스트리밍 중단/0 Token/서명 무효: 자가 치유 메커니즘 및 문제 해결 경로&quot;">​</a></h1><p>Antigravity Tools에서 <code>/v1/messages</code>(Anthropic 호환) 또는 Gemini 네이티브 스트리밍 인터페이스를 호출할 때 &quot;스트리밍 출력 중단&quot;, &quot;200 OK이지만 0 Token&quot;, &quot;Invalid <code>signature</code>&quot;와 같은 문제를 만나면, 이 과정은 UI에서 로그까지 문제 해결 경로를 제공합니다.</p><h2 id="이-과정을-통해-할-수-있는-것" tabindex="-1">이 과정을 통해 할 수 있는 것 <a class="header-anchor" href="#이-과정을-통해-할-수-있는-것" aria-label="Permalink to &quot;이 과정을 통해 할 수 있는 것&quot;">​</a></h2><ul><li>0 Token/중단 문제가 프록시에서 보통 &quot;peek 사전 읽기&quot;에 의해 먼저 차단된다는 것을 알 수 있음</li><li>Proxy Monitor에서 이번 요청의 계정과 매핑 모델(<code>X-Account-Email</code> / <code>X-Mapped-Model</code>)을 확인할 수 있음</li><li>로그를 통해 &quot;상류 스트림 조기 종료&quot;, &quot;백오프 재시도&quot;, &quot;계정 로테이션&quot; 또는 &quot;서명 수정 재시도&quot;인지 판단할 수 있음</li><li>어떤 상황에서 프록시 자가 치유를 기다리고 어떤 상황에서 수동으로 개입해야 하는지 알 수 있음</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p>다음과 같은 &quot;현상&quot;을 볼 수 있지만 어디서부터 시작해야 할지 모를 수 있습니다:</p><ul><li>스트리밍 출력이 중간에 중단되고 클라이언트가 &quot;멈춤&quot;처럼 더 이상 진행하지 않음</li><li>200 OK이지만 <code>usage.output_tokens=0</code> 또는 내용이 비어 있음</li><li>400 오류에 <code>Invalid \\</code>signature`<code>, </code>Corrupted thought signature<code>, </code>must be `thinking`` 등이 나타남</li></ul><p>이러한 문제의 대부분은 &quot;요청을 잘못 작성한 것&quot;이 아니라 스트리밍 전송, 상류 속도 제한/변동, 또는 과거 메시지에 포함된 서명 블록이 상류 검증을 트리거한 것입니다. Antigravity Tools는 프록시 계층에서 여러 방어선을 만들었으며, 고정 경로에 따라 확인하기만 하면 어디서 막히는지 알 수 있습니다.</p><h2 id="_0-token이란" tabindex="-1">0 Token이란? <a class="header-anchor" href="#_0-token이란" aria-label="Permalink to &quot;0 Token이란?&quot;">​</a></h2><p><strong>0 Token</strong>은 보통 한 번의 요청이 최종적으로 반환하는 <code>output_tokens=0</code>이며 &quot;내용이 생성되지 않은 것&quot;처럼 보이는 것을 말합니다. Antigravity Tools에서 더 일반적인 원인은 &quot;스트리밍 응답이 실제 출력 전에 끝나거나 오류가 발생&quot;하는 것이지, 모델이 정말로 0개 토큰을 생성한 것이 아닙니다. 프록시는 peek 사전 읽기를 사용하여 이러한 빈 응답을 차단하고 재시도를 트리거하려고 시도합니다.</p><h2 id="프록시가-백그라운드에서-수행하는-세-가지-작업-먼저-멘탈-모델-구축" tabindex="-1">프록시가 백그라운드에서 수행하는 세 가지 작업(먼저 멘탈 모델 구축) <a class="header-anchor" href="#프록시가-백그라운드에서-수행하는-세-가지-작업-먼저-멘탈-모델-구축" aria-label="Permalink to &quot;프록시가 백그라운드에서 수행하는 세 가지 작업(먼저 멘탈 모델 구축)&quot;">​</a></h2><h3 id="_1-비스트리밍-요청이-자동으로-스트리밍으로-변환될-수-있음" tabindex="-1">1) 비스트리밍 요청이 자동으로 스트리밍으로 변환될 수 있음 <a class="header-anchor" href="#_1-비스트리밍-요청이-자동으로-스트리밍으로-변환될-수-있음" aria-label="Permalink to &quot;1) 비스트리밍 요청이 자동으로 스트리밍으로 변환될 수 있음&quot;">​</a></h3><p><code>/v1/messages</code> 경로에서 프록시는 내부적으로 &quot;클라이언트 비스트리밍 요청&quot;을 스트리밍 요청으로 변환하여 상류에 요청하고, SSE를 받은 후 JSON으로 수집하여 반환합니다(이렇게 하는 이유는 로그에 &quot;better quota&quot;라고 명시되어 있음).</p><p>소스 코드 증거: <code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>.</p><h3 id="_2-peek-사전-읽기-첫-번째-유효-데이터-를-기다렸다가-클라이언트에-스트림-전달" tabindex="-1">2) Peek 사전 읽기: &quot;첫 번째 유효 데이터&quot;를 기다렸다가 클라이언트에 스트림 전달 <a class="header-anchor" href="#_2-peek-사전-읽기-첫-번째-유효-데이터-를-기다렸다가-클라이언트에-스트림-전달" aria-label="Permalink to &quot;2) Peek 사전 읽기: &quot;첫 번째 유효 데이터&quot;를 기다렸다가 클라이언트에 스트림 전달&quot;">​</a></h3><p><code>/v1/messages</code>의 SSE 출력에 대해 프록시는 먼저 <code>timeout + next()</code>로 사전 읽기를 하여 하트비트/주석 행(<code>:</code>로 시작)을 건너뛰고, 첫 번째 &quot;비어 있지 않고 하트비트가 아닌&quot; 데이터를 얻을 때까지 기다렸다가 공식적으로 전달합니다. peek 단계에서 오류/시간 초과/스트림 종료가 발생하면 직접 다음 시도로 들어갑니다(다음 시도는 보통 계정 로테이션을 트리거함).</p><p>소스 코드 증거: <code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code>; Gemini 네이티브 스트리밍도 유사한 peek가 있음: <code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>.</p><h3 id="_3-통합-백오프-재시도-상태-코드에-따라-계정-로테이션-여부-결정" tabindex="-1">3) 통합 백오프 재시도 + 상태 코드에 따라 &quot;계정 로테이션 여부&quot; 결정 <a class="header-anchor" href="#_3-통합-백오프-재시도-상태-코드에-따라-계정-로테이션-여부-결정" aria-label="Permalink to &quot;3) 통합 백오프 재시도 + 상태 코드에 따라 &quot;계정 로테이션 여부&quot; 결정&quot;">​</a></h3><p>프록시는 일반적인 상태 코드에 대해 명확한 백오프 전략을 만들었으며, 어떤 상태 코드가 계정 로테이션을 트리거하는지 정의했습니다.</p><p>소스 코드 증거: <code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>.</p><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><ul><li>Proxy Monitor를 열 수 있음(참조: <a href="./../../advanced/monitoring/">Proxy Monitor: 요청 로그, 필터, 세부 정보 복원 및 내보내기</a>)</li><li>로그가 데이터 디렉토리의 <code>logs/</code> 아래에 있다는 것을 알고 있음(참조: <a href="./../../start/first-run-data/">첫 시작 필수: 데이터 디렉토리, 로그, 트레이 및 자동 시작</a>)</li></ul><h2 id="따라-해보세요" tabindex="-1">따라 해보세요 <a class="header-anchor" href="#따라-해보세요" aria-label="Permalink to &quot;따라 해보세요&quot;">​</a></h2><h3 id="_1단계-호출-중인-인터페이스-경로-확인" tabindex="-1">1단계: 호출 중인 인터페이스 경로 확인 <a class="header-anchor" href="#_1단계-호출-중인-인터페이스-경로-확인" aria-label="Permalink to &quot;1단계: 호출 중인 인터페이스 경로 확인&quot;">​</a></h3><p><strong>이유</strong><code>/v1/messages</code>(claude handler)와 Gemini 네이티브(gemini handler)의 자가 치유 세부 정보가 다르므로, 경로를 먼저 확인하여 잘못된 로그 키워드에서 시간을 낭비하는 것을 방지합니다.</p><p>Proxy Monitor를 열고 실패한 요청을 찾아 먼저 Path를 기록하세요:</p><ul><li><code>/v1/messages</code>: <code>src-tauri/src/proxy/handlers/claude.rs</code>의 로직 보기</li><li><code>/v1beta/models/...:streamGenerateContent</code>: <code>src-tauri/src/proxy/handlers/gemini.rs</code>의 로직 보기</li></ul><p><strong>예상 결과</strong>: 요청 기록에서 URL/메서드/상태 코드(및 요청 소요 시간)를 볼 수 있습니다.</p><h3 id="_2단계-응답-헤더에서-계정-매핑-모델-잡기" tabindex="-1">2단계: 응답 헤더에서 &quot;계정 + 매핑 모델&quot; 잡기 <a class="header-anchor" href="#_2단계-응답-헤더에서-계정-매핑-모델-잡기" aria-label="Permalink to &quot;2단계: 응답 헤더에서 &quot;계정 + 매핑 모델&quot; 잡기&quot;">​</a></h3><p><strong>이유</strong> 동일한 요청이 실패/성공하는지는 종종 &quot;이번에 어떤 계정을 선택했는지&quot; &quot;어떤 상류 모델로 라우팅되었는지&quot;에 달려 있습니다. 프록시는 이 두 가지 정보를 응답 헤더에 쓰므로 먼저 기록하고 나중에 로그를 보고 대응할 수 있습니다.</p><p>실패한 요청에서 다음 응답 헤더를 찾으세요:</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>이 두 항목은 <code>/v1/messages</code>와 Gemini handler 모두에서 설정됩니다(예: <code>/v1/messages</code>의 SSE 응답: <code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code>; Gemini SSE: <code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>).</p><p><strong>예상 결과</strong>: <code>X-Account-Email</code>은 이메일이고 <code>X-Mapped-Model</code>은 실제 요청된 모델명입니다.</p><h3 id="_3단계-app-log에서-peek-단계에서-실패-인지-판단" tabindex="-1">3단계: app.log에서 &quot;peek 단계에서 실패&quot;인지 판단 <a class="header-anchor" href="#_3단계-app-log에서-peek-단계에서-실패-인지-판단" aria-label="Permalink to &quot;3단계: app.log에서 &quot;peek 단계에서 실패&quot;인지 판단&quot;">​</a></h3><p><strong>이유</strong> peek 실패는 보통 &quot;상류가 전혀 유효 데이터를 출력하지 않음&quot;을 의미합니다. 이러한 문제의 가장 일반적인 처리 방법은 재시도/계정 로테이션입니다. 프록시가 트리거했는지 확인해야 합니다.</p><p>먼저 로그 파일을 찾으세요(로그 디렉토리는 데이터 디렉토리의 <code>logs/</code>이며, 하루별로 <code>app.log*</code>에 롤링 작성됨).</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-Qfucc" id="tab-J-vExQP" checked><label data-title="macOS/Linux" for="tab-J-vExQP">macOS/Linux</label><input type="radio" name="group-Qfucc" id="tab-d3Ta1kl"><label data-title="Windows" for="tab-d3Ta1kl">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>그 다음 최신 <code>app.log*</code>에서 다음 키워드를 검색하세요:</p><ul><li><code>/v1/messages</code>(claude handler): <code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code>(<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>)</li><li>Gemini 네이티브 스트리밍: <code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code>(<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>)</li></ul><p><strong>예상 결과</strong>: peek 재시도가 트리거되면 로그에 &quot;retrying...&quot;와 유사한 경고가 나타나며 그 후 다음 시도 attempt로 들어갑니다(보통 계정 로테이션을 가져옴).</p><h3 id="_4단계-400-invalid-signature인-경우-프록시가-서명-수정-재시도-를-했는지-확인" tabindex="-1">4단계: 400/Invalid <code>signature</code>인 경우 프록시가 &quot;서명 수정 재시도&quot;를 했는지 확인 <a class="header-anchor" href="#_4단계-400-invalid-signature인-경우-프록시가-서명-수정-재시도-를-했는지-확인" aria-label="Permalink to &quot;4단계: 400/Invalid `signature`인 경우 프록시가 &quot;서명 수정 재시도&quot;를 했는지 확인&quot;">​</a></h3><p><strong>이유</strong> 서명 유형 오류는 종종 과거 메시지의 Thinking 블록/서명 블록이 상류 요구 사항에 맞지 않아서 발생합니다. Antigravity Tools는 &quot;과거 thinking 블록 다운그레이드 + 수정 프롬프트 주입&quot;으로 재시도를 시도합니다. 먼저 자가 치유가 완료되도록 해야 합니다.</p><p>다음 두 가지 신호로 수정 로직에 들어갔는지 판단할 수 있습니다:</p><ol><li>로그에 <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code>가 나타남(<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>)</li><li>이후 과거 <code>Thinking</code> 블록이 <code>Text</code>로 변환되고 마지막 user message에 수정 프롬프트가 추가됨(<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code>; Gemini handler도 <code>contents[].parts</code>에 동일한 프롬프트를 추가함: <code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>)</li></ol><p><strong>예상 결과</strong>: 프록시는 짧은 지연 후 자동으로 재시도(<code>FixedDelay</code>)하며 다음 시도 attempt로 들어갈 수 있습니다.</p><h2 id="확인-체크리스트-✅" tabindex="-1">확인 체크리스트 ✅ <a class="header-anchor" href="#확인-체크리스트-✅" aria-label="Permalink to &quot;확인 체크리스트 ✅&quot;">​</a></h2><ul><li>[ ] Proxy Monitor에서 요청 경로(<code>/v1/messages</code> 또는 Gemini 네이티브)를 확인할 수 있음</li><li>[ ] 이번 요청의 <code>X-Account-Email</code>과 <code>X-Mapped-Model</code>을 얻을 수 있음</li><li>[ ] <code>logs/app.log*</code>에서 peek/재시도 관련 키워드를 검색할 수 있음</li><li>[ ] 400 서명 오류를 만났을 때 프록시가 &quot;수정 프롬프트 + thinking 블록 정리&quot; 재시도 로직에 들어갔는지 확인할 수 있음</li></ul><h2 id="일반적인-문제" tabindex="-1">일반적인 문제 <a class="header-anchor" href="#일반적인-문제" aria-label="Permalink to &quot;일반적인 문제&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시나리오</th><th>할 수 있는 방법(❌)</th><th>권장 방법(✓)</th></tr></thead><tbody><tr><td>0 Token을 보면 즉시 수동으로 여러 번 재시도</td><td>클라이언트 재시도 버튼을 계속 누르고 로그를 전혀 보지 않음</td><td>먼저 Proxy Monitor + app.log를 한 번 보고 peek 단계 조기 종료인지 확인(자동 재시도/로테이션됨)</td></tr><tr><td><code>Invalid \\</code>signature``를 만나면 즉시 데이터 디렉토리를 비움</td><td><code>.antigravity_tools</code> 전체를 삭제하여 계정/통계 모두 사라짐</td><td>먼저 프록시가 &quot;서명 수정 재시도&quot;를 수행하게 하세요. 로그가 명확하게 복구 불가능하다고 표시할 때만 수동 개입 고려</td></tr><tr><td>&quot;서버 측 변동&quot;을 &quot;계정 고장&quot;으로 취급</td><td>400/503/529는 무조건 계정 로테이션</td><td>로테이션 효과 여부는 상태 코드에 따라 다름. 프록시 자체에 <code>should_rotate_account(...)</code> 규칙이 있음(<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</td></tr></tbody></table><h2 id="이-과정-요약" tabindex="-1">이 과정 요약 <a class="header-anchor" href="#이-과정-요약" aria-label="Permalink to &quot;이 과정 요약&quot;">​</a></h2><ul><li>0 Token/스트리밍 중단은 프록시에서 보통 먼저 peek 사전 읽기를 거침. peek 단계 실패는 재시도를 트리거하고 다음 attempt attempt로 들어감</li><li><code>/v1/messages</code>는 비스트리밍 요청을 내부적으로 스트리밍으로 변환한 후 JSON으로 다시 수집할 수 있으므로 &quot;왜 스트리밍 문제처럼 보이는지&quot; 이해에 영향을 줌</li><li>서명 무효 유형 400 오류는 프록시가 &quot;수정 프롬프트 + thinking 블록 정리&quot;로 재시도를 시도하므로 이 자가 치유 경로가 통과하는지 우선 확인</li></ul><h2 id="다음-과정-예고" tabindex="-1">다음 과정 예고 <a class="header-anchor" href="#다음-과정-예고" aria-label="Permalink to &quot;다음 과정 예고&quot;">​</a></h2><blockquote><p>다음 과정에서는 **<a href="./../../appendix/endpoints/">엔드포인트 빠른 참조표</a>**를 학습합니다.</p></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 펼치기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>Claude handler: 백오프 재시도 전략 + 로테이션 규칙</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L117-L236" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>117-236</td></tr><tr><td>Claude handler: 내부에서 비스트리밍을 스트리밍으로 변환(better quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L665-L776" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>665-776</td></tr><tr><td>Claude handler: peek 사전 읽기(하트비트/주석 건너뜀, 빈 스트림 방지)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L812-L926" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>812-926</td></tr><tr><td>Claude handler: 400 서명/블록 순서 오류 수정 재시도</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L999-L1102" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>999-1102</td></tr><tr><td>Gemini handler: peek 사전 읽기(빈 스트림 200 OK 방지)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L117-L149" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>117-149</td></tr><tr><td>Gemini handler: 400 서명 오류 수정 프롬프트 주입</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L300-L325" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>300-325</td></tr><tr><td>서명 캐시(세 계층: tool/family/session, TTL/최소 길이 포함)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/signature_cache.rs#L5-L207" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/signature_cache.rs</code></a></td><td>5-207</td></tr><tr><td>Claude SSE 변환: 서명 캡처 및 서명 캐시 작성</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/mappers/claude/streaming.rs#L639-L787" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></a></td><td>639-787</td></tr></tbody></table><p><strong>핵심 상수</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: 최대 재시시 횟수(<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>)</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> 초: 서명 캐시 TTL(<code>src-tauri/src/proxy/signature_cache.rs#L6</code>)</li><li><code>MIN_SIGNATURE_LENGTH = 50</code>: 서명 최소 길이(<code>src-tauri/src/proxy/signature_cache.rs#L7</code>)</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>determine_retry_strategy(...)</code>: 상태 코드에 따라 백오프 전략 선택(<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>)</li><li><code>should_rotate_account(...)</code>: 상태 코드에 따라 계정 로테이션 여부 결정(<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</li><li><code>SignatureCache::cache_session_signature(...)</code>: 세션 서명 캐시(<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>)</li></ul></details>',57)])])}const g=t(i,[["render",s]]);export{p as __pageData,g as default};
